#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Level;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEnemyNames.WraithVanguard)]
    public class WraithVanguard : AIEntityBehaviour
    {
        public WraithVanguard(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            if (!entity.HasBuff<WraithBuff>())
            {
                entity.AddBuff<WraithBuff>();
            }

            var buff = entity.AddBuff<FlyBuff>();
            buff.SetProperty(FlyBuff.PROP_TARGET_HEIGHT, 1f);

            if (!entity.HasBuff<VanguardResistanceBuff>())
            {
                entity.AddBuff<VanguardResistanceBuff>();
            }

        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            entity.SetModelDamagePercent();
            if (!entity.HasBuff<WraithBuff>())
            {
                entity.AddBuff<WraithBuff>();
            }

            if (entity.State == STATE_MELEE_ATTACK)
            {
                // 攻击时移除减伤buff  
                if (entity.HasBuff<VanguardResistanceBuff>())
                {
                    entity.RemoveBuffs<VanguardResistanceBuff>();
                }
                WitherAOE(entity, 2f, entity.GetFaction());
            }
            else
            {
                // 不攻击时添加减伤buff  
                if (!entity.HasBuff<VanguardResistanceBuff>())
                {
                    entity.AddBuff<VanguardResistanceBuff>();
                }
            }
        }

        public static void WitherAOE(Entity entity, float damage, int faction)
        {

            var range = 80;

            entity.Explode(
                entity.GetCenter(),
                range,
                faction,
                damage,
                new DamageEffectList(VanillaDamageEffects.DAMAGE_BOTH_ARMOR_AND_BODY, VanillaDamageEffects.MUTE, VanillaDamageEffects.WITHER, VanillaDamageEffects.WITHER)
            );


        }
        public const int STATE_MELEE_ATTACK = LogicEnemyStates.MELEE_ATTACK;
    }
}
